/**
 * FILES_INFO SCANNER — the Index law (engineering/MEDIA_SPEC.md §2).
 *
 * `files_info` is not hand-authored: it is regenerated by scanning the
 * filesystem for every quality × extension of a media identity. This module
 * ports PHP get_files_info (:1343) / get_quality_file_info (:2496) so the stored
 * DB index can be recomputed byte-compatibly. Values (size, dd_date file_time,
 * relative path) mirror PHP exactly, so a fresh scan of an untouched file
 * reproduces the stored entry.
 *
 * The dd_date `time` field is the Dédalo virtual-calendar encoding (fixed
 * 372-day years / 31-day months), NOT a Unix timestamp — shared with the record
 * lifecycle (create_record.virtualDateNow).
 */

import { existsSync, statSync } from 'node:fs';
import { config } from '../../config/config.ts';
import { type MediaTypeSpec, assertValidQuality } from '../concepts/media.ts';
import { type MediaIdentity, type MediaPathOptions, buildMediaLocation } from './path.ts';

/** One files_info entry (PHP get_quality_file_info shape). */
export interface FileInfoEntry {
	quality: string;
	file_exist: boolean;
	file_name: string | null;
	/** Media-root-relative path, leading slash (PHP str_replace(MEDIA_PATH,'')). External → the URL. */
	file_path: string | null;
	file_size: number | null;
	file_time: DdDate | null;
	extension: string | null;
	external?: boolean;
}

/** The dd_date object PHP stores for file_time (virtual-calendar encoded). */
export interface DdDate {
	day: number;
	hour: number;
	time: number;
	year: number;
	month: number;
	minute: number;
	second: number;
	timestamp: string;
}

/** Build the dd_date object from a file mtime (PHP dd_date::get_dd_date_from_timestamp + set_time). */
export function ddDateFromMtime(mtime: Date): DdDate {
	const year = mtime.getFullYear();
	const month = mtime.getMonth() + 1;
	const day = mtime.getDate();
	const hour = mtime.getHours();
	const minute = mtime.getMinutes();
	const second = mtime.getSeconds();
	const time =
		year * 372 * 86400 +
		(month - 1) * 31 * 86400 +
		(day - 1) * 86400 +
		hour * 3600 +
		minute * 60 +
		second;
	const pad = (v: number): string => String(v).padStart(2, '0');
	const timestamp = `${year}-${pad(month)}-${pad(day)} ${pad(hour)}:${pad(minute)}:${pad(second)}`;
	return { day, hour, time, year, month, minute, second, timestamp };
}

/** External source (stored data[0]) drives an external files_info entry. */
export interface ScanContext {
	/** External URL override (PHP get_external_source); when set, entries are external. */
	externalSource?: string | null;
	/** Stored data[0].original_normalized_name (e.g. 'rsc29_rsc170_770.tif'). */
	originalNormalizedName?: string | null;
	/** Stored data[0].modified_normalized_name (image retouched, e.g. '…_770.psd'). */
	modifiedNormalizedName?: string | null;
}

/**
 * One quality/extension file info (PHP get_quality_file_info :2496). Returns an
 * empty (file_exist:false) entry when the file is absent. External sources
 * short-circuit to an external entry.
 */
export function getQualityFileInfo(
	spec: MediaTypeSpec,
	identity: MediaIdentity,
	quality: string,
	extension: string,
	pathOpts: MediaPathOptions,
	context: ScanContext = {},
): FileInfoEntry {
	if (context.externalSource != null && context.externalSource !== '') {
		const ext = context.externalSource.split('.').pop() ?? '';
		return {
			quality,
			file_exist: true,
			file_name: null,
			file_path: context.externalSource,
			file_size: null,
			file_time: null,
			extension: ext,
			external: true,
		};
	}
	assertValidQuality(spec, quality);
	const location = buildMediaLocation(spec, identity, quality, extension, pathOpts);
	if (!existsSync(location.absolutePath)) {
		return {
			quality,
			file_exist: false,
			file_name: null,
			file_path: null,
			file_size: null,
			file_time: null,
			extension: null,
		};
	}
	const stats = statSync(location.absolutePath);
	const fileName = location.relativePath.slice(location.relativePath.lastIndexOf('/') + 1);
	return {
		quality,
		file_exist: true,
		file_name: fileName,
		file_path: location.relativePath,
		file_size: stats.size,
		file_time: ddDateFromMtime(stats.mtime),
		extension,
	};
}

/**
 * Scan the full files_info for a media identity (PHP get_files_info :1343).
 * For each quality: the thumb tier uses the thumb extension; every other tier
 * iterates unique([default, ...allowed, ...alternate]) extensions. Absent files
 * are skipped (include_empty=false parity). The raw+normalized `original` twin
 * and the image `modified` twin are appended from the stored names.
 */
export function scanFilesInfo(
	spec: MediaTypeSpec,
	identity: MediaIdentity,
	pathOpts: MediaPathOptions,
	context: ScanContext = {},
	includeEmpty = false,
): FileInfoEntry[] {
	// External source: PHP get_files_info short-circuits nothing, but every entry
	// resolves to the same external URL — emit one per list quality for shape parity.
	if (context.externalSource != null && context.externalSource !== '') {
		return spec.listQualities.map((quality) =>
			getQualityFileInfo(spec, identity, quality, spec.defaultExtension, pathOpts, context),
		);
	}

	const thumbQuality = config.media.thumb.quality;
	const thumbExtension = config.media.thumb.extension;
	const qualities = [...spec.qualities];
	if (spec.hasThumb && !qualities.includes(thumbQuality)) {
		qualities.push(thumbQuality);
	}
	const extensions = uniqueLower([
		spec.defaultExtension,
		...spec.allowedExtensions,
		...spec.alternateExtensions,
	]);

	const filesInfo: FileInfoEntry[] = [];
	for (const quality of qualities) {
		if (quality === thumbQuality) {
			const entry = getQualityFileInfo(spec, identity, quality, thumbExtension, pathOpts, context);
			if (includeEmpty || entry.file_exist) filesInfo.push(entry);
			continue;
		}
		for (const extension of extensions) {
			const entry = getQualityFileInfo(spec, identity, quality, extension, pathOpts, context);
			if (includeEmpty || entry.file_exist) filesInfo.push(entry);
		}
	}

	// original_normalized_name twin (e.g. the raw '.tif' next to the normalized '.jpg').
	appendNormalizedTwin(
		filesInfo,
		spec,
		identity,
		spec.originalQuality,
		context.originalNormalizedName,
		pathOpts,
	);
	// modified_normalized_name twin (image retouched tier, DEDALO_IMAGE_QUALITY_RETOUCHED).
	appendNormalizedTwin(
		filesInfo,
		spec,
		identity,
		config.media.imageQualityRetouched,
		context.modifiedNormalizedName,
		pathOpts,
	);

	return filesInfo;
}

/** Append the raw-original (or modified) normalized-name entry if that file exists. */
function appendNormalizedTwin(
	filesInfo: FileInfoEntry[],
	spec: MediaTypeSpec,
	identity: MediaIdentity,
	quality: string,
	normalizedName: string | null | undefined,
	pathOpts: MediaPathOptions,
): void {
	if (normalizedName == null || normalizedName === '') return;
	if (!spec.qualities.includes(quality)) return;
	const extension = normalizedName.split('.').pop() ?? '';
	if (extension === '') return;
	const entry = getQualityFileInfo(spec, identity, quality, extension, pathOpts, {});
	if (entry.file_exist && !filesInfo.some((e) => e.file_path === entry.file_path)) {
		filesInfo.push(entry);
	}
}

/** Lowercase + de-duplicate an extension list, preserving first-seen order. */
function uniqueLower(values: string[]): string[] {
	const seen = new Set<string>();
	const out: string[] = [];
	for (const value of values) {
		const lower = value.toLowerCase();
		if (!seen.has(lower)) {
			seen.add(lower);
			out.push(lower);
		}
	}
	return out;
}

/**
 * Save-time hook: re-scan and splice a fresh files_info into a stored media
 * item, PRESERVING the sibling keys (original_* / modified_* / lib_data) PHP
 * keeps in data[0] (PHP update_component_data_files_info :3710).
 */
export function refreshStoredFilesInfo(
	storedItem: Record<string, unknown>,
	spec: MediaTypeSpec,
	identity: MediaIdentity,
	pathOpts: MediaPathOptions,
): Record<string, unknown> {
	const context: ScanContext = {
		externalSource: (storedItem.external_source as string) ?? null,
		originalNormalizedName: (storedItem.original_normalized_name as string) ?? null,
		modifiedNormalizedName: (storedItem.modified_normalized_name as string) ?? null,
	};
	const filesInfo = scanFilesInfo(spec, identity, pathOpts, context);
	return { ...storedItem, files_info: filesInfo };
}
